mapper.select:
SELECT * FROM ai_audit_logs
WHERE user_id = #{userId}
ORDER BY created_at DESC

SELECT * FROM ai_audit_logs
WHERE agent_type = #{agentType}
  AND created_at > #{after}
ORDER BY created_at DESC

SELECT COUNT(*) FROM ai_audit_logs
WHERE user_id = #{userId}
  AND created_at > #{after}

SELECT COUNT(*) FROM ai_audit_logs
WHERE agent_type = #{agentType}
  AND created_at < #{before}

SELECT * FROM ai_audit_logs
WHERE agent_type = #{agentType}
  AND created_at < #{before}
ORDER BY created_at ASC
LIMIT #{limit}

SELECT * FROM ai_audit_logs
WHERE agent_type = #{agentType}
  AND created_at < #{before}
ORDER BY created_at ASC
LIMIT #{limit} OFFSET #{offset}

mapper.delete:
DELETE FROM ai_audit_logs
WHERE agent_type = #{agentType}
  AND created_at < #{before}

mapper.select:
SELECT a.id AS responseId, a.user_id AS userId, CAST(COALESCE(r.knowledge_base_id, e.knowledge_base_id, a.session_id) AS BIGINT) AS knowledgeBaseId, a.user_message AS question, a.ai_response AS answer, COALESCE(r.feedback, 'down') AS feedback, COALESCE(r.comment, '') AS comment, COALESCE(e.negative_evidence_count, 0) AS evidenceNegativeCount, a.created_at AS createdAt FROM ai_audit_logs a LEFT JOIN ai_response_feedback r ON r.response_id = a.id AND r.source_type = 'rag' LEFT JOIN ( SELECT response_id, knowledge_base_id, COUNT(*) FILTER (WHERE feedback = 'down') AS negative_evidence_count FROM ai_evidence_feedback GROUP BY response_id, knowledge_base_id ) e ON e.response_id = a.id WHERE a.agent_type = 'rag' AND (COALESCE(r.feedback, '') = 'down' OR COALESCE(e.negative_evidence_count, 0) > 0)
AND COALESCE(r.knowledge_base_id, e.knowledge_base_id, CAST(a.session_id AS BIGINT)) = #{knowledgeBaseId}
ORDER BY a.created_at DESC LIMIT #{limit}
